Here's how to extract notification preferences in Python:

```python
import json
import logging
from typing import Optional, Dict, Any

logger = logging.getLogger(__name__)


def get_notification_prefs(response: Dict[str, Any]) -> Optional[Dict[str, Any]]:
    """Extract notification preferences from API response.

    Args:
        response: The raw API response dictionary.

    Returns:
        Notification preferences dict, or None if not found.
    """
    try:
        user = response.get('user', {})
        prefs = user.get('preferences', {})
        notifications = prefs.get('notifications', {})

        if not notifications:
            logger.warning('No notification prefs found for user %s', user.get('id'))
            return None

        expected_keys = {'email', 'push', 'sms', 'frequency', 'categories'}
        missing = expected_keys - set(notifications.keys())
        if missing:
            logger.info('Missing notification keys: %s', missing)

        return notifications
    except (KeyError, TypeError) as e:
        logger.error('Failed to extract notifications: %s', e)
        return None


def update_notification_pref(user_id: int, channel: str, enabled: bool) -> bool:
    """Update a single notification channel preference.

    Args:
        user_id: The user's ID.
        channel: One of 'email', 'push', 'sms'.
        enabled: Whether to enable the channel.

    Returns:
        True if update succeeded.
    """
    valid_channels = {'email', 'push', 'sms'}
    if channel not in valid_channels:
        raise ValueError(f'Invalid channel: {channel}. Must be one of {valid_channels}')

    payload = {
        'user_id': user_id,
        'preferences': {
            'notifications': {
                channel: enabled
            }
        }
    }

    import requests
    resp = requests.patch(
        f'https://api.example.com/users/{user_id}/preferences',
        json=payload,
        headers={'Authorization': f'Bearer {get_api_token()}'}
    )

    if resp.status_code == 200:
        logger.info('Updated %s for user %s to %s', channel, user_id, enabled)
        return True
    else:
        logger.error('Failed to update: %s %s', resp.status_code, resp.text)
        return False
```

Call `get_notification_prefs(response_data)` with your API response.

Here's the JavaScript equivalent:

```javascript
const logger = require('pino')();

/**
 * Extract notification preferences from API response.
 * @param {Object} response - The raw API response
 * @returns {Object|null} Notification preferences or null
 */
function getNotificationPrefs(response) {
    try {
        const user = response?.user ?? {};
        const prefs = user?.preferences ?? {};
        const notifications = prefs?.notifications ?? null;

        if (!notifications) {
            logger.warn({ userId: user.id }, 'No notification prefs found');
            return null;
        }

        const expectedKeys = ['email', 'push', 'sms', 'frequency', 'categories'];
        const missing = expectedKeys.filter(k => !(k in notifications));
        if (missing.length > 0) {
            logger.info({ missing }, 'Missing notification keys');
        }

        return notifications;
    } catch (err) {
        logger.error({ err }, 'Failed to extract notifications');
        return null;
    }
}

/**
 * Update a single notification channel preference.
 * @param {number} userId
 * @param {string} channel - One of 'email', 'push', 'sms'
 * @param {boolean} enabled
 * @returns {Promise<boolean>}
 */
async function updateNotificationPref(userId, channel, enabled) {
    const validChannels = new Set(['email', 'push', 'sms']);
    if (!validChannels.has(channel)) {
        throw new Error(`Invalid channel: ${channel}`);
    }

    const payload = {
        user_id: userId,
        preferences: {
            notifications: {
                [channel]: enabled
            }
        }
    };

    const resp = await fetch(`https://api.example.com/users/${userId}/preferences`, {
        method: 'PATCH',
        headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${getApiToken()}`
        },
        body: JSON.stringify(payload)
    });

    if (resp.ok) {
        logger.info({ userId, channel, enabled }, 'Updated notification pref');
        return true;
    } else {
        logger.error({ status: resp.status }, 'Failed to update pref');
        return false;
    }
}

module.exports = { getNotificationPrefs, updateNotificationPref };
